"""Script to reproduce the issue described in the PR."""
import sys
sys.path.insert(0, '/testbed')

# Simulate the Kubernetes environment
import os
import tempfile

# Create temporary cgroup files
tmpdir = tempfile.mkdtemp()
cpu_dir = os.path.join(tmpdir, "cpu")
os.makedirs(cpu_dir)

# Write the values from the PR description
with open(os.path.join(cpu_dir, "cpu.cfs_quota_us"), "w") as f:
    f.write("-1")
with open(os.path.join(cpu_dir, "cpu.cfs_period_us"), "w") as f:
    f.write("100000")
with open(os.path.join(cpu_dir, "cpu.shares"), "w") as f:
    f.write("2")

# Now test the function
from pylint.lint.run import _query_cpu, _cpu_count

# We need to mock the paths
import unittest.mock as mock

original_is_file = os.path.exists

def mocked_is_file(path):
    if "cpu.cfs_quota_us" in path:
        return os.path.exists(os.path.join(cpu_dir, "cpu.cfs_quota_us"))
    elif "cpu.cfs_period_us" in path:
        return os.path.exists(os.path.join(cpu_dir, "cpu.cfs_period_us"))
    elif "cpu.shares" in path:
        return os.path.exists(os.path.join(cpu_dir, "cpu.shares"))
    return original_is_file(path)

# Actually, let's just directly test the logic
# The issue: cpu_quota = -1, so the first branch is skipped
# Then cpu.shares = 2, so avail_cpu = int(2/1024) = 0
# This returns 0, which causes the crash

print("Testing _query_cpu logic...")
print(f"int(2/1024) = {int(2/1024)}")
print(f"int(50000/100000) = {int(50000/100000)}")
print("Both can be 0, which is the problem.")

# Let's test the actual function with mocked paths
from pathlib import Path

# Monkey-patch Path.is_file
original_is_file_method = Path.is_file

def mocked_is_file_method(self):
    name = str(self)
    if "cpu.cfs_quota_us" in name:
        return os.path.exists(os.path.join(cpu_dir, "cpu.cfs_quota_us"))
    elif "cpu.cfs_period_us" in name:
        return os.path.exists(os.path.join(cpu_dir, "cpu.cfs_period_us"))
    elif "cpu.shares" in name:
        return os.path.exists(os.path.join(cpu_dir, "cpu.shares"))
    return original_is_file_method(self)

# Also need to mock open
original_open = open

def mocked_open(path, *args, **kwargs):
    if "cpu.cfs_quota_us" in str(path):
        return original_open(os.path.join(cpu_dir, "cpu.cfs_quota_us"), *args, **kwargs)
    elif "cpu.cfs_period_us" in str(path):
        return original_open(os.path.join(cpu_dir, "cpu.cfs_period_us"), *args, **kwargs)
    elif "cpu.shares" in str(path):
        return original_open(os.path.join(cpu_dir, "cpu.shares"), *args, **kwargs)
    return original_open(path, *args, **kwargs)

with mock.patch.object(Path, 'is_file', mocked_is_file_method):
    with mock.patch('builtins.open', mocked_open):
        result = _query_cpu()
        print(f"\n_query_cpu() returned: {result}")
        print(f"This is the bug: returns {result} instead of None or >= 1")

import shutil
shutil.rmtree(tmpdir)
